<script>

    function Error_Handler(e) {
        console.log(e);
        if (e.errors) {
            var message = ""Errors: \n"";
            $.each(e.errors, function (key, value) {
                if ('errors' in value) {
                    $.each(value.errors, function () {
                        message += this + ""\n"";
                    });
                }
            });
            alert(message);
        }


    };



</script>


